unitsize(1 cm);

pair A, B, O, P, Q, V;

A = (1,2);
B = (2,-1);
O = (0,0);
V = (3,-3);
P = (V + reflect(O,A)*(V))/2;

draw(O--V,Arrow(6));
draw(O--P,Arrow(6));
draw(P--V,Arrow(6));
draw((-1,0)--(4,0));
draw((0,-4)--(0,1));

label("$\begin{pmatrix} 3 \\ -3 \end{pmatrix}$", V, SE);
label("$\begin{pmatrix} -\frac{3}{5} \\ -\frac{6}{5} \end{pmatrix}$", P, W);
[/asy]

